"""Белый гауссов шум."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseNoiseclass GaussianNoise(BaseNoise):    name = "Белый гауссов шум"    description = "AWGN: независимые N(0,1), приведённые к целевому SNR."    params_schema = {        "target_snr_db": {"type": "float", "default": 10.0,                          "min": -40.0, "max": 80.0,                          "label": "Целевой SNR", "units": "дБ"},        "seed":          {"type": "int", "default": 42,                          "min": 0, "max": 2_147_483_647,                          "label": "Seed ГПСЧ"},    }    def _generate_raw(self, clean: Signal, p: dict,                      rng: np.random.Generator) -> np.ndarray:        return rng.standard_normal(size=clean.x.size).astype(np.float64, copy=False)